     1	//! Unified session management
     2	//!
     3	//! Provides a single `Session` type that optionally supports TEE processing,
     4	//! and a `SessionManager` that handles both regular and TEE session lifecycles.
     5	//!
     6	//! TEE processing is backed by `TeeRuntime` which detects the TEE environment
     7	//! at startup (Phase 11 architecture). SafeClaw runs as a guest inside the TEE,
     8	//! not as a host that boots VMs.
     9	
    10	use crate::audit::AuditEventBus;
    11	use crate::config::{SensitivityLevel, TeeConfig};
    12	use crate::error::{Error, Result};
    13	use crate::guard::{
    14	    FirewallResult, InjectionVerdict, InterceptResult, SanitizeResult, SessionIsolation,
    15	};
    16	use crate::privacy::{CumulativeRiskDecision, PrivacyPipeline, SessionPrivacyContext};
    17	use crate::tee::TeeRuntime;
    18	use dashmap::DashMap;
    19	use std::collections::HashMap;
    20	use std::sync::Arc;
    21	use tokio::sync::RwLock;
    22	use uuid::Uuid;
    23	
    24	/// Session state
    25	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    26	pub enum SessionState {
    27	    /// Session is being created
    28	    Creating,
    29	    /// Session is active
    30	    Active,
    31	    /// Session is processing a message (also covers TEE "Busy")
    32	    Processing,
    33	    /// Session is paused
    34	    Paused,
    35	    /// Session is being terminated
    36	    Terminating,
    37	    /// Session has been terminated
    38	    Terminated,
    39	}
    40	
    41	/// A user session, optionally backed by a TEE environment.
    42	#[derive(Debug)]
    43	pub struct Session {
    44	    /// Session ID
    45	    pub id: String,
    46	    /// User ID
    47	    pub user_id: String,
    48	    /// Channel ID
    49	    pub channel_id: String,
    50	    /// Chat ID (channel-specific)
    51	    pub chat_id: String,
    52	    /// Current state
    53	    state: Arc<RwLock<SessionState>>,
    54	    /// Highest sensitivity level seen
    55	    sensitivity_level: Arc<RwLock<SensitivityLevel>>,
    56	    /// Creation timestamp
    57	    pub created_at: i64,
    58	    /// Last activity timestamp
    59	    last_activity: Arc<RwLock<i64>>,
    60	    /// Message count
    61	    message_count: Arc<RwLock<u64>>,
    62	    /// Session metadata
    63	    metadata: Arc<RwLock<HashMap<String, serde_json::Value>>>,
    64	    /// Whether this session has been upgraded to TEE
    65	    tee_active: Arc<RwLock<bool>>,
    66	    /// Per-session cumulative privacy context for split-message attack defense
    67	    privacy_context: Arc<RwLock<SessionPrivacyContext>>,
    68	}
    69	
    70	impl Session {
    71	    /// Create a new session
    72	    pub fn new(user_id: String, channel_id: String, chat_id: String) -> Self {
    73	        let now = chrono::Utc::now().timestamp_millis();
    74	        Self {
    75	            id: Uuid::new_v4().to_string(),
    76	            user_id,
    77	            channel_id,
    78	            chat_id,
    79	            state: Arc::new(RwLock::new(SessionState::Creating)),
    80	            sensitivity_level: Arc::new(RwLock::new(SensitivityLevel::Normal)),
    81	            created_at: now,
    82	            last_activity: Arc::new(RwLock::new(now)),
    83	            message_count: Arc::new(RwLock::new(0)),
    84	            metadata: Arc::new(RwLock::new(HashMap::new())),
    85	            tee_active: Arc::new(RwLock::new(false)),
    86	            privacy_context: Arc::new(RwLock::new(SessionPrivacyContext::new())),
    87	        }
    88	    }
    89	
    90	    /// Get current state
    91	    pub async fn state(&self) -> SessionState {
    92	        *self.state.read().await
    93	    }
    94	
    95	    /// Set state
    96	    pub async fn set_state(&self, state: SessionState) {
    97	        *self.state.write().await = state;
    98	    }
    99	
   100	    /// Check if session is active
   101	    pub async fn is_active(&self) -> bool {
   102	        matches!(
   103	            self.state().await,
   104	            SessionState::Active | SessionState::Processing
   105	        )
   106	    }
   107	
   108	    /// Update last activity
   109	    pub async fn touch(&self) {
   110	        *self.last_activity.write().await = chrono::Utc::now().timestamp_millis();
   111	    }
   112	
   113	    /// Get last activity timestamp
   114	    pub async fn last_activity(&self) -> i64 {
   115	        *self.last_activity.read().await
   116	    }
   117	
   118	    /// Increment message count
   119	    pub async fn increment_messages(&self) {
   120	        *self.message_count.write().await += 1;
   121	    }
   122	
   123	    /// Get message count
   124	    pub async fn message_count(&self) -> u64 {
   125	        *self.message_count.read().await
   126	    }
   127	
   128	    /// Update sensitivity level (only increases)
   129	    pub async fn update_sensitivity(&self, level: SensitivityLevel) {
   130	        let mut current = self.sensitivity_level.write().await;
   131	        if level as u8 > *current as u8 {
   132	            *current = level;
   133	        }
   134	    }
   135	
   136	    /// Get current sensitivity level
   137	    pub async fn sensitivity_level(&self) -> SensitivityLevel {
   138	        *self.sensitivity_level.read().await
   139	    }
   140	
   141	    /// Record PII disclosures from a classification result.
   142	    ///
   143	    /// Called by `SessionRouter::route()` after each message is classified.
   144	    /// Feeds the cumulative privacy context used for split-message attack detection.
   145	    pub async fn record_disclosures(&self, rule_names: &[String], sensitivity: SensitivityLevel) {
   146	        self.privacy_context
   147	            .write()
   148	            .await
   149	            .record_disclosures(rule_names, sensitivity);
   150	    }

